create table rmais_invoices_events (
    efd_header_id     number,
    evento            varchar2(80 byte),
    mensagem          varchar2(1000 byte),
    creation_date     date,
    user_name         varchar2(1000 byte),
    access_key_number varchar2(50 byte)
);


